    /** * Se ejecuta cuando se detecta un error sintáctico tratable.
     * Reemplaza el mensaje genérico de CUP por uno con el lexema exacto.
     */
    @Override
    public void syntax_error(Symbol cur_token) {
        int linea   = cur_token.left;
        int columna = cur_token.right;
        
        // Extraemos el valor del token fallido (el lexema)
        String lexema = (cur_token.value != null) ? cur_token.value.toString() : "EOF / Desconocido";
        
        String mensaje = "No se esperaba el componente léxico: '" + lexema + "'. Verifica la estructura.";
        
        ErrorManager.getInstance().agregarSintactico(mensaje, linea, columna);
    }

    /** * Se ejecuta cuando el parser no puede continuar (pánico).
     * Sobrescribir este método APAGA los mensajes feos de NetBeans en consola
     * ("instead expected token classes...") y los reporta en la interfaz.
     */
    @Override
    public void unrecovered_syntax_error(Symbol cur_token) throws java.lang.Exception {
        int linea   = cur_token.left;
        int columna = cur_token.right;
        
        String lexema = (cur_token.value != null) ? cur_token.value.toString() : "Fin de Archivo (EOF)";
        String mensaje = "Estructura incompleta o corrupta cerca de: '" + lexema + "'. Se interrumpió el análisis.";
        
        ErrorManager.getInstance().agregarSintactico(mensaje, linea, columna);
    }

    /** Fallback silenciado para evitar errores duplicados en la interfaz */
    @Override
    public void report_error(String message, Object info) {
        // Vaciado intencionalmente. Toda la gestión ocurre en syntax_error.
    }

    /** Fallback silenciado para evitar crashes */
    @Override
    public void report_fatal_error(String message, Object info) {
        // Vaciado intencionalmente. Toda la gestión ocurre en unrecovered_syntax_error.
    }


